# Destructuring

**Category**: Advanced Features → Patterns  
**Purpose**: Extract values from complex data structures

---

## Overview

Destructuring **unpacks** data structures into individual variables.

---

## Tuple Destructuring

```aria
point: (i32, i32) = (10, 20);

// Destructure into variables
(x, y): (i32, i32) = point;

stdout << "$x, $y";  // 10, 20
```

---

## Struct Destructuring

```aria
struct Point {
    x: i32,
    y: i32,
}

p: Point = Point { x: 10, y: 20 };

// Destructure fields
Point { x, y } = p;

stdout << "$x, $y";  // 10, 20
```

---

## Partial Destructuring

```aria
struct User {
    name: string,
    age: i32,
    email: string,
}

user: User = User {
    name: "Alice",
    age: 30,
    email: "alice@example.com",
};

// Extract only needed fields
User { name, .. } = user;

stdout << name;  // "Alice"
```

---

## Renaming Fields

```aria
struct Config {
    host: string,
    port: i32,
}

config: Config = Config { host: "localhost", port: 8080 };

// Rename during destructuring
Config { host: server, port: server_port } = config;

stdout << "$server:$server_port";  // localhost:8080
```

---

## Array Destructuring

```aria
numbers: []i32 = [1, 2, 3, 4, 5];

// First two elements
[first, second, ...rest] = numbers;

stdout << "First: $first";   // First: 1
stdout << "Second: $second"; // Second: 2
stdout << "Rest: $rest";     // Rest: [3, 4, 5]
```

---

## Nested Destructuring

```aria
struct Address {
    street: string,
    city: string,
}

struct Person {
    name: string,
    address: Address,
}

person: Person = Person {
    name: "Alice",
    address: Address {
        street: "123 Main St",
        city: "Springfield",
    },
};

// Nested destructuring
Person { name, address: Address { city, .. } } = person;

stdout << "$name from $city";  // Alice from Springfield
```

---

## Function Parameters

```aria
fn print_point((x, y): (i32, i32)) {
    stdout << "Point at ($x, $y)";
}

fn greet(User { name, age, .. }: User) {
    stdout << "Hello $name, age $age";
}

fn main() {
    print_point((10, 20));

    user: User = User { name: "Bob", age: 25, email: "bob@example.com" };
    greet(user);
}
```

---

## Match Destructuring

```aria
enum Message {
    Quit,
    Move(i32, i32),
    Write(string),
    ChangeColor(i32, i32, i32),
}

fn process(msg: Message) {
    match msg {
        Message.Quit => {
            stdout << "Quitting";
        }
        Message.Move(x, y) => {
            stdout << "Moving to ($x, $y)";
        }
        Message.Write(text) => {
            stdout << "Writing: $text";
        }
        Message.ChangeColor(r, g, b) => {
            stdout << "Color: RGB($r, $g, $b)";
        }
    }
}
```

