## If-Let Destructuring

```aria
fn process_optional(opt: ?Point) {
    if let Some(Point { x, y }) = opt {
        stdout << "Point at ($x, $y)";
    } else {
        stdout << "No point";
    }
}

fn handle_result(Result: Result<User>) {
    if let Ok(User { name, age, .. }) = result {
        stdout << "$name is $age years old";
