## While-Let Destructuring

```aria
fn process_iter(iter: Iterator<(string, i32)>) {
    while let Some((key, value)) = iter.next() {
        stdout << "$key = $value";
    }
}

fn process_results(results: []Result<Data>) {
    i: i32 = 0;
