fn parse_program() -> Result<Program> {
    declarations: []Declaration = [];
    errors: []string = [];

    while !self.is_at_end() {
        match self.parse_declaration() {
            Ok(decl) => declarations.push(decl),
            Err(e) => {
                errors.push(e);
                self.synchronize();
            }
        }
    }

    if errors.len() > 0 {
        return Err(errors.join("\n"));
    }

    return Ok(Program { declarations });
}
