func:merge_i32 = NIL(int32->:arr, int32:left, int32:mid, int32:right, int32->:temp) {
int32:i = left;
    int32:j = mid + 1;
    int32:k = left;

    // Merge the two halves into temp array
    while (i <= mid && j <= right) {
        if (arr[i] <= arr[j]) {
            temp[k] = arr[i];
            i = i + 1;
        } else {
            temp[k] = arr[j];
            j = j + 1;
        }
        k = k + 1;
    }

    // Copy remaining elements from left half
    while (i <= mid) {
        temp[k] = arr[i];
        i = i + 1;
        k = k + 1;
    }

    // Copy remaining elements from right half
    while (j <= right) {
        temp[k] = arr[j];
        j = j + 1;
        k = k + 1;
    }

    // Copy back to original array
    i = left;
    till(right + 1, 1i64) {
        arr[i] = temp[i];
        i = i + 1;
    }
    pass(NIL);
};
}
