 * 3. Growth-Limited Arena (Long-Running Service):
 *    arena_result:res = new_arena(8192);
 *    arena@:service_arena = res.unwrap();
 *    defer destroy(service_arena);
 *    
 *    loop {
 *        // Keep max 1MB, free excess
 *        reset_limit(service_arena, 1048576);
 *        
 *        // Process...
 *    }
 */

/**
 * PERFORMANCE CHARACTERISTICS:
 * 
 * Operation          | Time       | Comparison
 * -------------------+------------+------------------
 * arena_alloc (hot)  | ~2ns       | 10-25x faster than malloc
 * arena_alloc (cold) | ~100ns     | Same as malloc (rare)
 * reset (retain)     | ~2ns       | O(1) vs O(N) free
 * destroy            | O(blocks)  | Typically < 10 blocks
 * 
 * Memory Overhead:
 * - Per block: 24 bytes (header)
 * - Per allocation: 0 bytes (no metadata!)
 * - Alignment padding: Up to (align - 1) bytes
 * 
 * Optimal Use Cases:
 * - Compiler passes (many small AST nodes)
 * - Request handling (HTTP servers)
 * - Parsing (token/tree allocation)
 * - Temporary buffers (sort, filter, map)
 * 
 * Avoid When:
 * - Objects have destructors (use GC or manual free)
 * - Long-lived objects (use GC)
 * - Mixed lifetimes (some objects outlive others)
 */

/**
 * SAFETY CONSIDERATIONS:
 * 
 * 1. Use-After-Reset:
 *    alloc_result<int64>:res = arena_alloc<int64>(arena);
 *    wild int64->:ptr = res.unwrap();
 *    ptr@ = 42;
