func:partition_i32 = int32(int32->:arr, int32:low, int32:high) {
int32:pivot = arr[high];
    int32:i = low - 1;

    int32:j = low;
    till(high, 1i64) {
        if (arr[j] < pivot) {
            i = i + 1;
            // Swap arr[i] and arr[j]
            int32:temp = arr[i];
            arr[i] = arr[j];
            arr[j] = temp;
        }
        j = j + 1;
    }

    // Swap arr[i+1] and arr[high] (pivot)
    int32:temp = arr[i + 1];
    arr[i + 1] = arr[high];
    arr[high] = temp;

    return i + 1;
};
}
